      "id": "real_time_news_search",
      "slug": "real-time-news-search",
      "basePath": "/real-time-news-search",
      "title": "Real-Time News Search",
      "version": "1.0.0",
      "description": "Fast and Reliable News Search API - Search and Retrieve News Articles, Top Stories, Sources, Publication Dates, Thumbnails, and More from Google Search in Real-Time.",
      "operations": {
        "search": {
          "method": "GET",
          "path": "/search",
          "summary": "Search",
          "description": "Search Google News for any query and get real-time news results. Returns a top stories cluster (when available for the query), main news results with article metadata, source info, thumbnails, and published dates (both localized relative text and ISO 8601 UTC). Supports pagination, filtering by time period or custom date range, country, language, sort order, and safe search.",
          "pathParams": [],
          "queryParams": [
            "query",
            "page",
            "country",
            "language",
            "time_period",
            "date_from",
            "date_to",
            "sort_by",
            "safe"
          ],
          "bodyParams": [],
          "inputSchema": {
            "type": "object",
            "properties": {
              "query": {
                "type": "string",
                "description": "The news search query.\n\n**Examples:**\n\n`climate change`\n\n`artificial intelligence startups`\n\n`bitcoin price 2026`"
              },
              "page": {
                "type": "integer",
                "default": 1,
                "minimum": 1,
                "description": "Page number for pagination. Each page returns up to 10 news results.\n\n**Allowed values:** `1` and above."
              },
              "country": {
                "type": "string",
                "default": "us",
                "description": "Country code of the country to return news results for. See https://en.wikipedia.org/wiki/ISO_3166-1_alpha-2 for supported values.\n\n**Default:** `us`"
              },
              "language": {
                "type": "string",
                "default": "en",
                "description": "The language of the results, specified as a 2-letter language code - see ISO 639-1.\n\n**Default:** `en`"
              },
              "time_period": {
                "type": "string",
                "enum": [
                  "any",
                  "last_hour",
                  "last_day",
                  "last_week",
                  "last_month",
                  "last_year"
                ],
                "default": "any",
                "description": "Filter results to a specific time period. Cannot be used together with `date_from`/`date_to`.\n\n**Allowed values:** `any`, `last_hour`, `last_day`, `last_week`, `last_month`, `last_year`\n\n**Default:** `any`"
              },
              "date_from": {
                "type": "string",
                "description": "Start date for a custom date range filter, in `MM/DD/YYYY` format. Must be provided together with `date_to`. Cannot be used together with `time_period` (other than `any`).\n\n**Example:** `01/01/2026`"
              },
              "date_to": {
                "type": "string",
                "description": "End date for a custom date range filter, in `MM/DD/YYYY` format. Must be provided together with `date_from`.\n\n**Example:** `04/10/2026`"
              },
              "sort_by": {
                "type": "string",
                "enum": [
                  "relevance",
                  "date"
                ],
                "default": "relevance",
                "description": "Sort order for the results.\n\n**Allowed values:** `relevance`, `date`\n\n**Default:** `relevance`"
              },
              "safe": {
                "type": "string",
                "enum": [
                  "off",
                  "active"
                ],
                "default": "off",
                "description": "Safe search setting to filter explicit content.\n\n**Allowed values:** `off`, `active`\n\n**Default:** `off`"
              }
            },
            "required": [
              "query"
            ]
          }
        }
      }
